    def __init__(self, limit):
        self.limit = limit
        self.spent = 0

    def add_expense(self, amount):
        if amount < 0:
            return self.spent
        self.spent += amount
        return self.spent

    def remaining(self):
        return max(0, self.limit - self.spent)

    def is_over_budget(self):
        return self.spent > self.limit"
